1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	interface Policy {
32	  items: Item[];
33	  remainingCap: number;
34	}
35	
36	type QuoteResult = { premium: number };
37	type ClaimResult = { payout: number; remainingCap: number };
38	type StepResult = QuoteResult | ClaimResult;
39	
40	const BASE_PREMIUM: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: 25,
46	};
47	
48	const INSURANCE_VALUE: Record<string, number> = {
49	  sword: 1000,
50	  amulet: 600,
51	  staff: 800,
52	  potion: 400,
53	  rune: 250,
54	  moonstone: 250,
55	};
56	
57	const DEDUCTIBLE = 100;
58	const CAP_MULTIPLIER = 2;
59	
60	const FIRST_INSURANCE_RATE = 0.1;
61	const CURSE_RATE = 0.5;
62	const HIGH_ENCH_RATE = 0.3;
63	const HIGH_ENCH_THRESHOLD = 5;
64	const LOYALTY_RATE = 0.2;
65	const LOYALTY_THRESHOLD = 2;
66	const FOLLOWUP_RATE = 0.15;
67	const PROCESSING_FEE = 5;
68	
69	const COMPONENT_PREMIUM = 25;
70	const BLOCK_SIZE = 3;
71	const BLOCK_PREMIUM = 60;
72	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
73	
74	const componentBasePremium = (count: number): number =>
75	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
76	
77	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
78	
79	const isMainItem = (item: Item): boolean => !isComponent(item);
80	
81	const countByType = (items: Item[]): Map<string, number> =>
82	  items.reduce(
83	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
84	    new Map<string, number>(),
85	  );
86	
87	const componentTotal = (items: Item[]): number =>
88	  [...countByType(items.filter(isComponent)).values()].reduce(
89	    (sum, count) => sum + componentBasePremium(count),
90	    0,
91	  );
92	
93	const basePremium = (items: Item[]): number => {
94	  const mainTotal = items
95	    .filter(isMainItem)
96	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
97	  return mainTotal + componentTotal(items);
98	};
99	
100	const mainItemBase = (item: Item): number => BASE_PREMIUM[item.type];
101	
102	const surchargeFor = (
103	  items: Item[],
104	  qualifies: (item: Item) => boolean,
105	  rate: number,
106	): number =>
107	  items
108	    .filter((item) => isMainItem(item) && qualifies(item))
109	    .reduce((sum, item) => sum + mainItemBase(item) * rate, 0);
110	
111	const isCursed = (item: Item): boolean => item.cursed === true;
112	
113	const curseSurcharge = (items: Item[]): number =>
114	  surchargeFor(items, isCursed, CURSE_RATE);
115	
116	const isHighlyEnchanted = (item: Item): boolean =>
117	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
118	
119	const highEnchantmentSurcharge = (items: Item[]): number =>
120	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCH_RATE);
121	
122	const discountWhen = (policyBase: number, qualifies: boolean, rate: number): number =>
123	  qualifies ? policyBase * rate : 0;
124	
125	const isLoyal = (years: number): boolean => years >= LOYALTY_THRESHOLD;
126	
127	const quotePremium = (items: Item[], years: number, isFollowUp: boolean): number => {
128	  const policyBase = basePremium(items);
129	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
130	  const itemSurcharges = curseSurcharge(items) + highEnchantmentSurcharge(items);
131	  const loyalty = discountWhen(policyBase, isLoyal(years), LOYALTY_RATE);
132	  const followUp = discountWhen(policyBase, isFollowUp, FOLLOWUP_RATE);
133	  return Math.ceil(
134	    policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE,
135	  );
136	};
137	
138	const insuranceSum = (items: Item[]): number =>
139	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
140	
141	const damagePayout = (damage: Damage): number =>
142	  Math.max(damage.amount - DEDUCTIBLE, 0);
143	
144	const processClaim = (policy: Policy, claim: ClaimStep): ClaimResult => {
145	  const payout = claim.incident.damages.reduce(
146	    (sum, damage) => sum + damagePayout(damage),
147	    0,
148	  );
149	  policy.remainingCap -= payout;
150	  return { payout, remainingCap: policy.remainingCap };
151	};
152	
153	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
154	  const years = scenario.customer.yearsWithMHPCO;
155	  const policies: Policy[] = [];
156	  let quoteCount = 0;
157	  const results = scenario.steps.map((step, index): StepResult => {
158	    if (step.op === "quote") {
159	      const premium = quotePremium(step.items, years, quoteCount > 0);
160	      quoteCount += 1;
161	      policies[index] = {
162	        items: step.items,
163	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
164	      };
165	      return { premium };
166	    }
167	    return processClaim(policies[step.policy], step);
168	  });
169	  return { results };
170	};
